from __future__ import annotations
import base64,io,shutil,subprocess,sys,tarfile
from pathlib import Path
REPO=Path(__file__).resolve().parent
PARTS=sorted((REPO/'.ssp-v1.8.7-delta').glob('part-*'))
if len(PARTS)!=7: raise SystemExit(f'Expected 7 governed delta parts, found {len(PARTS)}.')
payload=base64.b64decode(''.join(p.read_text().strip() for p in PARTS))
release=REPO/'modules/ssp/releases/v1.8.7'
release.mkdir(parents=True,exist_ok=True)
with tarfile.open(fileobj=io.BytesIO(payload),mode='r:xz') as archive:
    for member in archive.getmembers():
        target=(release/member.name).resolve()
        if target!=release.resolve() and release.resolve() not in target.parents: raise SystemExit(f'Unsafe path: {member.name}')
        if member.isdir(): target.mkdir(parents=True,exist_ok=True); continue
        if not member.isfile(): raise SystemExit(f'Unsupported member: {member.name}')
        target.parent.mkdir(parents=True,exist_ok=True)
        source=archive.extractfile(member)
        if source is None: raise SystemExit(f'Unreadable member: {member.name}')
        with source,target.open('wb') as destination: shutil.copyfileobj(source,destination)
source_dir=release/'source';source_dir.mkdir(parents=True,exist_ok=True)
shutil.copy2(REPO/'modules/ssp/releases/v1.8.6/CMMC_L2_SSP_Modern_Editable_v1.8.6.html',source_dir/'CMMC_L2_SSP_Modern_Editable_v1.8.6.html')
subprocess.run([sys.executable,str(release/'materialize.py')],cwd=REPO,check=True)
FILES={'README.md':'','modules/ssp/README.md':'','modules/ssp/current/release.json':'','tests/playwright/module-catalog.mjs':'','modules/ssp/releases/v1.8.5/materialize.py':''}
for relative,encoded in FILES.items():
    path=REPO/relative;path.parent.mkdir(parents=True,exist_ok=True);path.write_bytes(base64.b64decode(encoded))
shutil.rmtree(REPO/'.ssp-v1.8.7-delta',ignore_errors=True)
Path(__file__).unlink(missing_ok=True)
paths=['README.md','modules/ssp/README.md','modules/ssp/current/release.json','modules/ssp/releases/v1.8.5/materialize.py','modules/ssp/releases/v1.8.7','tests/playwright/module-catalog.mjs','.ssp-v1.8.7-delta','.ssp-v1.8.7-materialize.py']
subprocess.run(['git','add','-A','--',*paths],cwd=REPO,check=True)
if subprocess.run(['git','diff','--cached','--quiet'],cwd=REPO).returncode:
    subprocess.run(['git','config','user.name','github-actions[bot]'],cwd=REPO,check=True)
    subprocess.run(['git','config','user.email','41898282+github-actions[bot]@users.noreply.github.com'],cwd=REPO,check=True)
    subprocess.run(['git','commit','-m','Materialize governed SSP v1.8.7 release'],cwd=REPO,check=True)
    subprocess.run(['git','push'],cwd=REPO,check=True)
